WITH RECURSIVE a(x) AS (SELECT 1 UNION ALL SELECT x+1 FROM a WHERE x < 5), b(y) AS (SELECT TRUE IN (VALUES (NULL) EXCEPT SELECT CURRENT_TIMESTAMP ORDER BY CURRENT_TIMESTAMP COLLATE NOCASE COLLATE NOCASE) FROM a) SELECT *, count(*) FILTER (WHERE RAISE(IGNORE)) OVER (PARTITION BY RAISE(IGNORE) ORDER BY CURRENT_TIME DESC NULLS LAST ROWS BETWEEN CURRENT ROW AND UNBOUNDED FOLLOWING) FROM b;